    <script>
        // --- Buggy Counter Logic ---
        let buggyCount = 0;
        const buggyCountDisplay = document.getElementById('buggyCountDisplay');
        const buggyIncrementButton = document.getElementById('buggyIncrementButton');

        buggyIncrementButton.addEventListener('click', () => {
            // Simulate an asynchronous operation (e.g., fetching data, complex calculation)
            // that takes some time.
            setTimeout(() => {
                // Buggy read-modify-write cycle
                const currentValue = buggyCount; // READ: Get the current value
                const newValue = currentValue + 1; // MODIFY: Calculate the new value
                buggyCount = newValue; // WRITE: Update the shared variable
                buggyCountDisplay.textContent = buggyCount; // Update UI
            }, 100); // A small delay to make the race condition more apparent
        });


        // --- Corrected Counter Logic ---
        let correctedCount = 0;
        const correctedCountDisplay = document.getElementById('correctedCountDisplay');
        const correctedIncrementButton = document.getElementById('correctedIncrementButton');

        // A queue to hold pending increment operations
        const updateQueue = [];
        let isProcessingQueue = false;

        // Function to simulate an async increment and update the UI
        function asyncIncrementCorrected() {
            return new Promise(resolve => {
                setTimeout(() => {
                    correctedCount++; // Directly increment, as this is the only operation touching it now
                    correctedCountDisplay.textContent = correctedCount;
                    resolve();
                }, 100); // Same delay as the buggy version
            });
        }

        // Function to process the queue
        async function processQueue() {
            if (isProcessingQueue) return; // Already processing

            isProcessingQueue = true;
            while (updateQueue.length > 0) {
                const operation = updateQueue.shift(); // Get the next operation
                await operation(); // Wait for it to complete
            }
            isProcessingQueue = false;
        }

        correctedIncrementButton.addEventListener('click', () => {
            // Add the increment operation to the queue
            updateQueue.push(asyncIncrementCorrected);
            // Start processing the queue if not already
            processQueue();
        });

    </script>
