            // Step 1: READ the current value
            const currentValue = buggyCounter;

            // Step 2: Simulate an asynchronous delay (e.g., network request, complex calculation)
            setTimeout(() => {
                // Step 3: MODIFY the value based on what was READ *earlier*
                const newValue = currentValue + 1;

                // Step 4: WRITE the new value
                buggyCounter = newValue;
                buggyCounterDisplay.textContent = buggyCounter;
            }, 100); // 100ms delay to expose the race condition
        }

        buggyIncrementBtn.addEventListener('click', incrementBuggy);

        // --- Fixed Counter Logic ---
        let fixedCounter = 0;
        const fixedCounterDisplay = document.getElementById('fixedCounterDisplay');
        const fixedIncrementBtn = document.getElementById('fixedIncrementBtn');

        let isProcessing = false; // A flag to indicate if an increment operation is currently in progress
        const pendingIncrements = []; // A queue to hold pending increment requests

        function incrementFixed() {
            pendingIncrements.push(1); // Add an increment request to the queue
            processQueue(); // Attempt to process the queue
        }

        function processQueue() {
            // If an operation is already processing OR the queue is empty, do nothing
            if (isProcessing || pendingIncrements.length === 0) {
                return;
            }

            isProcessing = true; // Mark that we are now processing an item
            pendingIncrements.shift(); // Take one increment request from the front of the queue

            // Step 1: READ the current value (this read happens *after* previous operations have completed their write)
            const currentValue = fixedCounter;

            // Step 2: Simulate an asynchronous delay
            setTimeout(() => {
                // Step 3: MODIFY based on the *latest* read
                const newValue = currentValue + 1;

                // Step 4: WRITE the new value
                fixedCounter = newValue;
                fixedCounterDisplay.textContent = fixedCounter;

                isProcessing = false; // Mark that this operation is complete
                processQueue();       // Immediately try to process the next item in the queue
            }, 100); // 100ms delay
